%[text] #### Animation $\\Psi$ plane Agent vs Brute Force
%% Animation
figure; %[output:9d89afbd]
h_img = imagesc(1:EnvPars.T_x, 1:EnvPars.T_y, R_max_per_frame(:,:,1)); %[output:9d89afbd]
axis square; colorbar; hold on; %[output:9d89afbd]

% Common color scale across frames
clim([min(R_max_per_frame(:)), max(R_max_per_frame(:))]); %[output:9d89afbd]

% % --- Agent (black) ---
% Trail of past agent actions
h_trail_agent = plot(agent_tx(1), agent_ty(1), '-', ... %[output:9d89afbd]
                     'Color', [0 0 0 0.4], 'LineWidth', 1.2); %[output:9d89afbd]
% Past action markers (dim)
h_past_agent  = plot(agent_tx(1), agent_ty(1), 'ko', 'MarkerSize', 6, ... %[output:9d89afbd]
                     'MarkerFaceColor',[0.6 0.6 0.6], 'MarkerEdgeColor','k'); %[output:9d89afbd]
%Current agent action (bright)
h_agent       = plot(agent_tx(1), agent_ty(1), 'ks', 'MarkerSize', 14, ... %[output:9d89afbd]
                     'MarkerFaceColor', 'k', 'LineWidth', 1.5); %[output:9d89afbd]

% --- Brute-force optimum (red) ---
% Trail of past optima
h_trail_brute_force   = plot(tx_brute_force_per_frame(1), ty_brute_force_per_frame(1), '-', ... %[output:9d89afbd]
                     'Color', [1 0 0 0.4], 'LineWidth', 1.2); %[output:9d89afbd]
% Past optimum markers (dim red)
h_past_brute_force    = plot(tx_brute_force_per_frame(1), ty_brute_force_per_frame(1), 'rx', ... %[output:9d89afbd]
                     'MarkerSize', 8, 'LineWidth', 1.0, ... %[output:9d89afbd]
                     'Color', [1 0.6 0.6]); %[output:9d89afbd]
% Current optimum (bright red)
h_opt_brute_force         = plot(tx_brute_force_per_frame(1), ty_brute_force_per_frame(1), 'rx', ... %[output:9d89afbd]
                     'MarkerSize', 16, 'LineWidth', 2.5); %[output:9d89afbd]

xlabel('$n_{\psi_x}$','Interpreter','latex'); %[output:9d89afbd]
ylabel('$n_{\psi_y}$','Interpreter','latex'); %[output:9d89afbd]
h_title = title(sprintf('Peak 2D-DFT, $t=$ %.1fs / %.1fs', delta_time, time_simul), ... %[output:9d89afbd]
                'Interpreter','latex'); %[output:9d89afbd]
% legend([h_agent, h_opt_brute_force], {'Agent action','Brute-force optimum'}, ...
%        'Location','southwest','Interpreter','latex');
set(gca,'FontSize',font); %[output:9d89afbd]

xlim([0.5 EnvPars.T_x+0.5]); ylim([0.5 EnvPars.T_y+0.5]); %[output:9d89afbd]

for k = 1:Nsteps-1 %[output:group:12e24cea]
    set(h_img, 'CData', R_max_per_frame(:,:,k));
    
    % Agent: trail, past markers, current
    set(h_trail_agent, 'XData', agent_tx(1:k),          'YData', agent_ty(1:k)); %[output:9d89afbd]
    set(h_past_agent,  'XData', agent_tx(1:max(1,k-1)), 'YData', agent_ty(1:max(1,k-1)));
    set(h_agent,       'XData', agent_tx(k),            'YData', agent_ty(k));
    
    % Optimum: trail, past markers, current
    set(h_trail_brute_force,   'XData', tx_brute_force_per_frame(1:k),          'YData', ty_brute_force_per_frame(1:k));
    set(h_past_brute_force,    'XData', tx_brute_force_per_frame(1:max(1,k-1)), 'YData', ty_brute_force_per_frame(1:max(1,k-1)));
    set(h_opt_brute_force,         'XData', tx_brute_force_per_frame(k),            'YData', ty_brute_force_per_frame(k));
    
    set(h_title, 'String', sprintf('Peak 2D-DFT, $t=$ %.1fs / %.1fs', k*delta_time, time_simul));
    drawnow;
    if k < Nsteps
        pause(0.05);
    end
end %[output:group:12e24cea]

