    psi_x_axis_per_frame(:,k) = 2*pi * ((1:EnvPars.N_x) - 1 + (tx_brute_force_per_frame(k)-1)/EnvPars.T_x) / EnvPars.N_x;
    psi_y_axis_per_frame(:,k) = 2*pi * ((1:EnvPars.N_y) - 1 + (tx_brute_force_per_frame(k)-1)/EnvPars.T_y) / EnvPars.N_y;
end

